import{_ as o,o as t,c as a,ag as n}from"./chunks/framework.BPmc_f4o.js";const m=JSON.parse('{"title":"Automations","description":"","frontmatter":{},"headers":[],"relativePath":"automations/automations.md","filePath":"automations/automations.md"}'),i={name:"automations/automations.md"};function s(r,e,l,h,d,c){return t(),a("div",null,[...e[0]||(e[0]=[n('<p><span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#1565c0;color:#fff;font-size:11px;font-weight:600;">PRO</span></p><h1 id="automations" tabindex="-1">Automations <a class="header-anchor" href="#automations" aria-label="Permalink to &quot;Automations&quot;">​</a></h1><p>Automations connect WordPress events to actions — send emails, fire webhooks, or dispatch custom hooks — without writing code. Each automation listens for one or more events, evaluates optional conditions, and executes its action list in sequence.</p><p>Automations are a Pro feature. In the free tier, a simplified event selector is available directly in the <a href="/webhooks/webhooks.html">Webhook editor</a>.</p><hr><h2 id="automations-list" tabindex="-1">Automations List <a class="header-anchor" href="#automations-list" aria-label="Permalink to &quot;Automations List&quot;">​</a></h2><ul><li><strong>Create</strong> a new automation with the add button.</li><li><strong>Enable / Disable</strong> an automation with the toggle. A confirmation is required before the change is applied.</li><li><strong>Delete</strong> an automation. A confirmation is required before deletion proceeds.</li></ul><hr><h2 id="automation-editor" tabindex="-1">Automation Editor <a class="header-anchor" href="#automation-editor" aria-label="Permalink to &quot;Automation Editor&quot;">​</a></h2><h3 id="identity" tabindex="-1">Identity <a class="header-anchor" href="#identity" aria-label="Permalink to &quot;Identity&quot;">​</a></h3><ul><li><strong>Title</strong> — display name used in the admin list.</li><li><strong>Description</strong> — optional notes for your own reference.</li></ul><h3 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to &quot;Events&quot;">​</a></h3><p>Select one or more events that trigger this automation. Available event categories:</p><ul><li><strong>WordPress Posts, Taxonomies &amp; Media</strong> — create, update, and delete events for posts, custom post types, taxonomy terms, and media.</li><li><strong>User events</strong> — user registration and login.</li><li><strong>WooCommerce</strong> — order, product, customer, and other WooCommerce lifecycle events (requires WooCommerce).</li><li><strong>Application Layer</strong> — internal plugin events (user access, rate limit exceeded, application changes, etc.).</li><li><strong>Custom Hooks</strong> — declare any WordPress action or filter hook by name. Configure the number of arguments the hook passes, name each argument, and choose which ones are forwarded to the action payload.</li><li><strong>Incoming Webhook</strong> — trigger this automation when an external service calls the application&#39;s <a href="/webhooks/webhooks.html#incoming-webhooks">incoming webhook endpoint</a>. The verified JSON payload from the external request is forwarded as automation arguments and is available in conditions and actions.</li></ul><h4 id="incoming-webhook-event" tabindex="-1">Incoming Webhook Event <a class="header-anchor" href="#incoming-webhook-event" aria-label="Permalink to &quot;Incoming Webhook Event&quot;">​</a></h4><p>When an automation uses <strong>Incoming Webhook</strong> as its event, it is connected to a specific <a href="/webhooks/webhooks.html#incoming-webhooks">incoming webhook entry</a> configured in the Webhooks panel. The incoming webhook entry provides the endpoint URL and HMAC key used to verify the external request.</p><p>Once the signature is verified, the automation fires with the <strong>parsed JSON body</strong> of the external request available as named arguments. You can:</p><ul><li>Reference any top-level field from the incoming payload in <strong>Conditions</strong> (e.g. <code>event</code>, <code>amount</code>, <code>status</code>).</li><li>Forward payload fields to outbound webhooks or email templates via <strong>Actions</strong>.</li></ul><p>This makes it straightforward to react to external events — a payment confirmation from Stripe, a build notification from GitHub, a status update from a third-party API — and chain them with any combination of WordPress actions.</p><h3 id="scheduled-trigger" tabindex="-1">Scheduled Trigger <a class="header-anchor" href="#scheduled-trigger" aria-label="Permalink to &quot;Scheduled Trigger&quot;">​</a></h3><p>For scheduled automations, hook data is queued or rotated as events fire. The release condition is either:</p><ul><li><strong>After N events</strong> — the accumulated data is flushed and the actions run once the queue reaches N hook events.</li><li><strong>On schedule</strong> — a WP-Cron interval releases the queued data at a fixed time, regardless of how many events have accumulated.</li></ul><h3 id="conditions" tabindex="-1">Conditions <a class="header-anchor" href="#conditions" aria-label="Permalink to &quot;Conditions&quot;">​</a></h3><p>An optional conditional logic block is evaluated before the action sequence runs. If the block fails, the automation halts.</p><p>Conditions are organised in <strong>AND / OR groups</strong>: within a group all conditions must pass (AND); the automation proceeds if any group passes (OR). Each condition inspects a named argument from the trigger hook — the argument list is derived from the hook configuration in the Events section.</p><h3 id="actions" tabindex="-1">Actions <a class="header-anchor" href="#actions" aria-label="Permalink to &quot;Actions&quot;">​</a></h3><p>Actions execute in order when the trigger fires (and conditions pass). Each action can be individually enabled or disabled without removing it. You can add <strong>as many actions as you need</strong> — multiple emails, multiple webhooks, or any combination.</p><ul><li><strong>Send Email</strong> — select an existing <a href="/mails/mails.html">Email template</a> or create a new one inline.</li><li><strong>Call Webhook</strong> — select an existing <a href="/webhooks/webhooks.html">Webhook entry</a> or create a new one inline.</li></ul><hr><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><p><strong>How do I trigger an automation from an external service?</strong></p><p>Create an <a href="/webhooks/webhooks.html#incoming-webhooks">incoming webhook entry</a> in the Webhooks panel, copy its endpoint URL, and point your external service at it. Connect the incoming webhook entry to this automation using the <strong>Automation</strong> field in the webhook editor. When a valid signed request arrives, this automation fires with the request payload available as arguments.</p><p><strong>Can an automation trigger another automation?</strong></p><p>Not yet. Direct automation chaining is not currently supported. It is a planned action type.</p><p><strong>Can one automation send multiple emails and fire multiple webhooks?</strong></p><p>Yes. Add as many <em>Send Email</em> and <em>Call Webhook</em> actions as you need. They execute in sequence, each pointing to a different template or webhook entry.</p><p><strong>What happens if one action in a sequence fails?</strong></p><p>By default execution continues to the next action. Failures are recorded in the application log with the automation ID and action index.</p>',38)])])}const g=o(i,[["render",s]]);export{m as __pageData,g as default};
